import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getMovies } from '../services/api';
import Hero from '../components/Hero';

const Home = () => {
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadMovies();
  }, []);

  const loadMovies = async () => {
    try {
      const data = await getMovies();
      setMovies(data);
    } catch (error) {
      console.error('Error cargando películas:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-[70vh]">
        <div className="animate-spin rounded-full h-16 w-16 border-t-2 border-b-2 border-stream-red"></div>
      </div>
    );
  }

  // Obtenemos una película destacada al azar o la primera
  const featuredMovie = movies.length > 0 ? movies[Math.floor(Math.random() * movies.length)] : null;

  // Separar en categorías para mostrar estantes (carruseles)
  const series = movies.filter(m => m.type === 'series');
  const peliculas = movies.filter(m => m.type !== 'series');

  const MovieRow = ({ title, items }) => (
    <div className="mb-12 px-6 md:px-12 animate-slide-up">
      <h2 className="text-2xl font-bold mb-6 flex items-center space-x-2">
        <span className="w-1.5 h-6 bg-stream-red rounded-full inline-block"></span>
        <span>{title}</span>
      </h2>

      <div className="flex overflow-x-auto gap-6 pb-8 pt-4 no-scrollbar -mt-4">
        {items.map(movie => (
          <Link 
            key={movie.id} 
            to={`/movie/${movie.id}`} 
            className="group relative min-w-[200px] w-[200px] md:min-w-[240px] md:w-[240px] transition-all duration-300 hover:scale-105 hover:z-20 cursor-pointer"
          >
            <div className="bg-stream-card rounded-xl overflow-hidden aspect-[2/3] ring-1 ring-white/5 shadow-lg relative">
              <img 
                src={movie.poster || 'https://images.unsplash.com/photo-1489599849927-2ee91cede3ba?ixlib=rb-4.0.3&auto=format&fit=crop&w=300&q=80'} 
                alt={movie.title}
                className="w-full h-full object-cover transition-opacity duration-300 group-hover:opacity-60"
                onError={(e) => {
                  e.target.src = 'https://images.unsplash.com/photo-1489599849927-2ee91cede3ba?ixlib=rb-4.0.3&auto=format&fit=crop&w=300&q=80';
                }}
              />
              {/* Información overlay en hover */}
              <div className="absolute inset-x-0 bottom-0 p-4 bg-gradient-to-t from-black/90 via-black/60 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                <h3 className="font-bold text-white truncate text-lg">{movie.title}</h3>
                <div className="flex items-center space-x-2 mt-1">
                  <span className="text-xs font-semibold text-green-400">98% Coincidencia</span>
                  <span className="text-xs text-gray-300">{movie.year}</span>
                </div>
              </div>
              {/* Play icon central */}
              <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                <div className="w-12 h-12 rounded-full bg-stream-red/90 flex items-center justify-center shadow-lg border border-white/20 pl-1">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" />
                  </svg>
                </div>
              </div>
            </div>
          </Link>
        ))}
        {items.length === 0 && (
           <div className="text-gray-400 italic">No hay contenido disponible.</div>
        )}
      </div>
    </div>
  );

  return (
    <div className="pb-10 -mt-20"> {/* Offset por el padding en App.js */}
      <Hero movie={featuredMovie} />

      <MovieRow title="Tendencias Ahora" items={movies.slice(0, 8)} />
      <MovieRow title="Series Más Vistas" items={series} />
      <MovieRow title="Aclamadas por la Crítica" items={peliculas} />
    </div>
  );
};

export default Home;
